/**
 * teiCrafter Pipeline -- Validator (P.6)
 *
 * Lightweight validation for pipeline-generated TEI-XML.
 * Works without DOM parser (Node.js compatible, no dependencies).
 *
 * Checks:
 * 1. Well-formedness (basic tag matching)
 * 2. Plaintext preservation (word-level similarity)
 * 3. Required header elements present
 */

/**
 * @typedef {Object} ValidationMessage
 * @property {'error'|'warning'|'info'} level
 * @property {'wellformed'|'plaintext'|'structure'} source
 * @property {string} message
 */

/**
 * Validate a TEI-XML string generated by the pipeline.
 *
 * @param {string} xml - The generated TEI-XML
 * @param {Object} pageJson - Original Page-JSON (for comparison)
 * @returns {ValidationMessage[]}
 */
export function validate(xml, pageJson) {
    const messages = [];

    messages.push(...checkWellFormedness(xml));
    messages.push(...checkRequiredElements(xml));
    messages.push(...checkPlaintextPreservation(xml, pageJson));

    return messages;
}

/**
 * Basic well-formedness check using tag-stack matching.
 * Not a full XML parser, but catches common errors.
 */
function checkWellFormedness(xml) {
    const messages = [];

    // Check XML declaration
    if (!xml.startsWith('<?xml')) {
        messages.push({ level: 'warning', source: 'wellformed', message: 'Missing XML declaration.' });
    }

    // Check matching tags
    const tagPattern = /<\/?([a-zA-Z][a-zA-Z0-9]*)[^>]*\/?>/g;
    const stack = [];
    let match;

    while ((match = tagPattern.exec(xml)) !== null) {
        const full = match[0];
        const tag = match[1];

        if (full.endsWith('/>')) continue; // self-closing
        if (full.startsWith('<?')) continue; // processing instruction

        if (full.startsWith('</')) {
            // Closing tag
            if (stack.length === 0) {
                messages.push({ level: 'error', source: 'wellformed', message: `Unexpected closing tag </${tag}>.` });
                return messages;
            }
            const expected = stack.pop();
            if (expected !== tag) {
                messages.push({
                    level: 'error',
                    source: 'wellformed',
                    message: `Mismatched tags: expected </${expected}>, found </${tag}>.`
                });
                return messages;
            }
        } else {
            // Opening tag
            stack.push(tag);
        }
    }

    if (stack.length > 0) {
        messages.push({
            level: 'error',
            source: 'wellformed',
            message: `Unclosed tags: ${stack.join(', ')}.`
        });
    } else {
        messages.push({ level: 'info', source: 'wellformed', message: 'Tag structure is well-formed.' });
    }

    return messages;
}

/**
 * Check that required TEI structure elements are present.
 */
function checkRequiredElements(xml) {
    const messages = [];

    const required = [
        ['<TEI', 'Root element <TEI>'],
        ['<teiHeader', 'Element <teiHeader>'],
        ['<fileDesc', 'Element <fileDesc>'],
        ['<titleStmt', 'Element <titleStmt>'],
        ['<title', 'Element <title>'],
        ['<sourceDesc', 'Element <sourceDesc>'],
        ['<msDesc', 'Element <msDesc>'],
        ['<msIdentifier', 'Element <msIdentifier>'],
        ['<text', 'Element <text>'],
        ['<body', 'Element <body>'],
        ['<div', 'At least one <div>']
    ];

    let missing = 0;
    for (const [pattern, label] of required) {
        if (!xml.includes(pattern)) {
            messages.push({ level: 'error', source: 'structure', message: `Missing: ${label}.` });
            missing++;
        }
    }

    if (missing === 0) {
        messages.push({ level: 'info', source: 'structure', message: 'All required elements present.' });
    }

    return messages;
}

/**
 * Check that the original plaintext is preserved in the TEI output.
 * Compares word sets between original page texts and body content.
 */
function checkPlaintextPreservation(xml, pageJson) {
    const messages = [];

    // Extract original text from Page-JSON
    const originalWords = new Set();
    for (const page of (pageJson.pages || [])) {
        if (page.type !== 'content' || !page.text) continue;
        for (const w of page.text.toLowerCase().split(/\s+/)) {
            if (w) originalWords.add(w);
        }
    }

    if (originalWords.size === 0) {
        messages.push({ level: 'info', source: 'plaintext', message: 'No content pages -- nothing to compare.' });
        return messages;
    }

    // Extract text from body in the XML (strip all tags)
    const bodyMatch = xml.match(/<body>([\s\S]*)<\/body>/);
    if (!bodyMatch) {
        messages.push({ level: 'error', source: 'plaintext', message: 'No <body> found in output.' });
        return messages;
    }

    const bodyText = bodyMatch[1].replace(/<[^>]+>/g, ' ');
    const bodyWords = new Set();
    for (const w of bodyText.toLowerCase().split(/\s+/)) {
        if (w) bodyWords.add(w);
    }

    // Jaccard-like: intersection / original
    let common = 0;
    for (const w of originalWords) {
        if (bodyWords.has(w)) common++;
    }

    const similarity = Math.round((common / originalWords.size) * 100);

    if (similarity >= 95) {
        messages.push({
            level: 'info',
            source: 'plaintext',
            message: `Plaintext preservation: ${similarity}% of original words found in output.`
        });
    } else {
        messages.push({
            level: similarity >= 80 ? 'warning' : 'error',
            source: 'plaintext',
            message: `Plaintext divergence: only ${similarity}% of original words found in output.`
        });
    }

    return messages;
}

/**
 * Format validation results as a human-readable summary.
 * @param {ValidationMessage[]} messages
 * @returns {string}
 */
export function formatReport(messages) {
    const errors = messages.filter(m => m.level === 'error');
    const warnings = messages.filter(m => m.level === 'warning');
    const infos = messages.filter(m => m.level === 'info');

    const lines = [];
    if (errors.length) {
        lines.push(`ERRORS (${errors.length}):`);
        for (const e of errors) lines.push(`  [${e.source}] ${e.message}`);
    }
    if (warnings.length) {
        lines.push(`WARNINGS (${warnings.length}):`);
        for (const w of warnings) lines.push(`  [${w.source}] ${w.message}`);
    }
    if (infos.length) {
        lines.push(`OK (${infos.length}):`);
        for (const i of infos) lines.push(`  [${i.source}] ${i.message}`);
    }

    const status = errors.length ? 'FAIL' : warnings.length ? 'WARN' : 'PASS';
    lines.push(`\nResult: ${status}`);
    return lines.join('\n');
}
